
const LS={accounts:'nw_v4_accounts',session:'nw_v4_session',characters:'nw_v4_characters',campaigns:'nw_v4_campaigns'};
let DATA=null;
let FB={enabled:false,ready:false,loadingCloud:false,user:null,app:null,auth:null,db:null,mods:null,saveTimer:null,lastSync:'Local only'};
let state={view:'landing',tab:'dashboard',account:null,accounts:[],characters:[],campaigns:[],activeCharacterId:null,activeCampaignId:null,wizardStep:0,query:'',rolls:[],roller:{dice:'3d6',attr:'instinct',primary:'Awareness',support1:'none',support2:'none',setbacks:0}};
const $=s=>document.querySelector(s); const $$=s=>[...document.querySelectorAll(s)];
function esc(s=''){return String(s).replace(/[&<>'"]/g,c=>({'&':'&amp;','<':'&lt;','>':'&gt;',"'":'&#39;','"':'&quot;'}[c]))}
function uid(p='id'){return p+'_'+Date.now().toString(36)+'_'+Math.random().toString(36).slice(2,8)}
function save(k,v){localStorage.setItem(k,JSON.stringify(v))} function load(k,d){try{return JSON.parse(localStorage.getItem(k))??d}catch{return d}}
function clamp(n,min,max){n=Number(n)||0;return Math.max(min,Math.min(max,n))}
function persist(){save(LS.accounts,state.accounts);save(LS.characters,state.characters);save(LS.campaigns,state.campaigns);save(LS.session,state.account?{accountId:state.account.id,remember:!!state.account.remember}:null);queueCloudSave()}
function attrLabel(k){return DATA.attributes.find(a=>a.key===k)?.label||k}
function baseAttributes(){return {...DATA.baseAttributes}}
function roleObj(role){return DATA.roles[role]||DATA.roles.Tracker}
function rolePackage(role){let a=baseAttributes();Object.entries(roleObj(role).bonuses).forEach(([k,v])=>a[k]=(a[k]||9)+v);return a}
function allRoleSkills(role){let r=roleObj(role);return [...r.starter,...r.experienced,...r.master]}
function allSkills(){let s=new Set();Object.values(DATA.roles).forEach(r=>[...r.starter,...r.experienced,...r.master].forEach(x=>s.add(x)));(DATA.sharedSkills||[]).forEach(x=>s.add(x.name));(DATA.spells||[]).forEach(x=>s.add(x.name));return [...s].sort()}
function rank(ch,skill){return clamp(ch?.skills?.[skill]||0,0,3)}
function activeChar(){return state.characters.find(c=>c.id===state.activeCharacterId)||null} function activeCamp(){return state.campaigns.find(c=>c.id===state.activeCampaignId)||null}
function defaultCharacter(){return {id:uid('char'),created:new Date().toISOString(),updated:new Date().toISOString(),ownerId:state.account?.id||'local',profile:{name:'',lineage:'',age:'',role:'Tracker',height:'',weight:'',pronouns:'',backgroundAlias:'',image:''},lore:{concept:'',backstory:'',scar:'',fear:'',goals:'',contacts:''},appearance:{eyes:'',hair:'',build:'',style:'',notes:''},attributes:rolePackage('Tracker'),manualAttributeEdits:false,subfocus:{},skills:{},health:{healthy:4,wounded:0,critical:0,downed:false},marks:0,tier:1,equipment:[],notes:'',afflictions:'',startingPackage:''}}
function newCampaign(){let uidv=state.account?.id||'local';return {id:uid('camp'),ownerId:uidv,ownerUid:uidv,memberIds:[uidv],autoGM:false,name:'New Campaign',joinCode:Math.random().toString(36).slice(2,8).toUpperCase(),gm:state.account?.displayName||'GM',summary:'',players:state.account?[{id:uidv,name:state.account.displayName,email:state.account.email||'',role:'GM'}]:[],characters:[],chats:[{id:uid('chat'),name:'Table Chat',visibleTo:'all',members:[uidv],messages:[]}],created:new Date().toISOString(),updated:new Date().toISOString()}}
async function init(){try{DATA=await (await fetch('night_wardens_data.json',{cache:'no-store'})).json()}catch(e){alert('Could not load night_wardens_data.json. Make sure it is uploaded next to index.html.');DATA={baseAttributes:{force:9,prowess:9,intellect:9,instinct:9,will:9,charisma:9,endurance:9},attributes:[{key:'force',label:'Force'},{key:'prowess',label:'Prowess'},{key:'intellect',label:'Intellect'},{key:'instinct',label:'Instinct'},{key:'will',label:'Will'},{key:'charisma',label:'Charisma'},{key:'endurance',label:'Endurance'}],roles:{Tracker:{bonuses:{instinct:2,prowess:1,endurance:1},function:'Finds what does not want to be found.',starter:['Tracking','Survival','Awareness','Investigation','Stealth','Navigation'],experienced:['Ambush','Trap Avoidance','Environmental Reading','Pursuit'],master:['Supernatural Tracking','Kill Setup','Apex Predator']}},sharedSkills:[],gear:[],consumablesRelics:[],materials:[],spells:[],starterEquipmentPackages:{}}}
state.accounts=load(LS.accounts,[]);state.characters=load(LS.characters,[]);state.campaigns=load(LS.campaigns,[]);let sess=load(LS.session,null);if(sess?.remember){let acc=state.accounts.find(a=>a.id===sess.accountId);if(acc){state.account=acc;state.view='app'}}render();initFirebase()}
function render(){const app=$('#app'); if(!state.account||state.view==='landing') app.innerHTML=landing(); else app.innerHTML=shell()}
function landing(){return `<div class="landingWrap"><div class="landingBox" style="max-width:1080px;width:100%"><div class="hero"><div class="kicker">Night Wardens</div><h1>Night Wardens Digital Field Office</h1><p class="sub">Build Wardens, save campaigns, and run hunts from one field dossier.</p><nav class="nav"><a class="btn ghost" href="storefront.html">Storefront</a><a class="btn ghost" href="digital-library.html">Digital Library</a><a class="btn ghost" href="auto-gm.html">Auto-GM</a></nav></div><div class="grid cols2" style="margin-top:16px"><div class="card"><h2>Login</h2><p class="small">Use Google sync when configured, or local device login as a private offline fallback.</p><label>Email / Handle</label><input id="loginEmail" placeholder="warden@example.com"><label style="margin-top:8px">Display Name</label><input id="loginName" placeholder="Anthony"><div class="row" style="margin-top:10px"><input id="remember" type="checkbox" style="width:auto"><label for="remember" style="margin:0">Remember me / auto-login</label></div><button class="btn full" style="margin-top:12px" onclick="loginLocal()">Login / Create Local Account</button><button class="btn ghost full" style="margin-top:8px" onclick="signInGoogle()">Continue with Google / Cloud Sync</button></div><div class="card"><h2>What Opens After Login</h2><div class="list"><div class="item"><b>Load Character</b><div class="small">View saved characters and open the one you want.</div></div><div class="item"><b>New Character</b><div class="small">Guided D&D Beyond-style creation: lore, backstory, appearance, role, attributes, skills, equipment.</div></div><div class="item"><b>Join Campaign</b><div class="small">Use a campaign code and save the campaign locally. Online invite syncing comes with Firebase/Supabase.</div></div></div><div class="divider"></div><label>Import Existing Vault</label><input type="file" accept="application/json" onchange="importVaultFromLanding(event)"></div></div></div></div>`}
async function googleSoon(){return signInGoogle()}
async function signInGoogle(){try{await initFirebase(true);if(!FB.ready) return alert('Firebase is not configured yet. Open firebase-config.js and paste your Firebase web config. Local login still works.');await FB.mods.signInWithPopup(FB.auth,FB.provider).catch(async()=>{await FB.mods.signInWithRedirect(FB.auth,FB.provider)});}catch(e){console.error(e);alert('Google sign-in failed: '+(e.message||e))}}
function loginLocal(){let email=($('#loginEmail').value||'local@nightwardens').trim().toLowerCase();let name=($('#loginName').value||email.split('@')[0]||'Warden').trim();let remember=$('#remember').checked;let acc=state.accounts.find(a=>a.email===email);if(!acc){acc={id:uid('acct'),email,displayName:name,created:new Date().toISOString()};state.accounts.push(acc)}acc.displayName=name;acc.remember=remember;state.account=acc;state.view='app';persist();render()}
async function logout(){if(!confirm('Log out on this device?'))return;try{if(FB.ready&&FB.auth?.currentUser)await FB.mods.signOut(FB.auth)}catch(e){}state.account=null;state.view='landing';save(LS.session,null);render()}
function shell(){return `<div class="wrap"><div class="hero"><div class="kicker">Classified Field Dossier</div><h1>Night Wardens</h1><p class="sub">Investigate first. Prepare second. Confront last.</p><nav class="nav noPrint"><a class="btn ghost" href="storefront.html">Storefront</a><a class="btn ghost" href="digital-library.html">Digital Library</a><a class="btn ghost" href="auto-gm.html">Auto-GM</a><a class="btn ghost" href="admin.html">Admin</a></nav><div class="topbar"><div class="profile"><div class="avatar">${esc((state.account.displayName||'W')[0].toUpperCase())}</div><div><b>${esc(state.account.displayName)}</b><div class="small">${esc(state.account.email||'local account')} · ${esc(FB.lastSync||'Local only')}</div></div></div><div class="row noPrint"><button class="btn ghost" onclick="state.tab='dashboard';render()">Home</button><button class="btn ghost" onclick="cloudSyncNow()">Cloud Sync</button><button class="btn ghost" onclick="exportVault()">Export Vault</button><label class="btn ghost">Import Vault<input type="file" accept="application/json" style="display:none" onchange="importVault(event)"></label><button class="btn bad" onclick="logout()">Logout</button></div></div></div>${nav()}<main id="panel">${panel()}</main></div>`}
function nav(){let tabs=[['dashboard','Landing'],['characters','Characters'],['create','New Character'],['level','Level Up'],['campaigns','Campaigns'],['grimoire','Grimoire'],['bestiary','Bestiary'],['library','Library'],['roller','Roller'],['reference','Quick Reference']];return `<div class="nav">${tabs.map(([k,l])=>`<button class="tab ${state.tab===k?'active':''}" onclick="state.tab='${k}';render()">${l}</button>`).join('')}</div>`}
function panel(){return {dashboard:dashboard,characters:charactersPage,create:wizard,level:levelPage,campaigns:campaignsPage,grimoire:grimoirePage,bestiary:bestiaryPage,library:library,roller:roller,reference:reference}[state.tab]?.()||dashboard()}
function renderPanel(){let p=$('#panel'); if(p)p.innerHTML=panel(); else render()}
function dashboard(){let recent=activeChar();return `<div class="grid dashboardGrid"><div class="card"><h2>Landing Actions</h2><button class="btn full" onclick="state.tab='characters';render()">Load Character</button><button class="btn secondary full" style="margin-top:8px" onclick="startNewCharacter()">New Character</button><button class="btn ghost full" style="margin-top:8px" onclick="state.tab='campaigns';render()">Join / Manage Campaign</button><div class="divider"></div><div class="note"><b>Autosave:</b> Characters and campaigns save to this device. Use Export Vault for backups or moving to another phone.</div></div><div class="grid cols2"><div class="card"><h2>Saved Characters</h2>${characterList(true)}</div><div class="card"><h2>Saved Campaigns</h2>${campaignList(true)}</div>${recent?`<div class="card"><h2>Active Character</h2>${characterSummary(recent)}<button class="btn" onclick="state.tab='level';render()">Level / Edit</button></div>`:''}<div class="card"><h2>Cloud Sync</h2><p>${esc(FB.lastSync||'Local only')}</p><div class="row"><button class="btn ghost" onclick="cloudPull()">Pull Cloud</button><button class="btn ghost" onclick="cloudPush()">Push Cloud</button></div><p class="small">Google sign-in, shared campaigns, member-only campaign docs, and cross-device sync are powered by Firebase Auth + Firestore when configured.</p></div></div></div>`}
function characterList(compact=false){let chars=state.characters.filter(c=>!state.account||!c.ownerId||c.ownerId===state.account.id||c.ownerId==='local'); if(!chars.length)return '<div class="item small">No characters saved yet.</div>';return `<div class="list">${chars.map(c=>`<div class="item ${state.activeCharacterId===c.id?'active':''}"><div class="row spread"><div class="row">${c.profile.image?`<img class="avatar" src="${c.profile.image}">`:`<div class="avatar">${esc((c.profile.name||'W')[0].toUpperCase())}</div>`}<div><b>${esc(c.profile.name||'Unnamed Warden')}</b><div class="small">${esc(c.profile.role)} · Tier ${c.tier||1} · Marks ${c.marks||0}</div></div></div></div><div class="row" style="margin-top:8px"><button class="btn ghost" onclick="selectCharacter('${c.id}')">Open</button><button class="btn ghost" onclick="downloadCharacter('${c.id}')">Export</button><button class="btn bad" onclick="deleteCharacter('${c.id}')">Delete</button></div></div>`).join('')}</div>`}
function charactersPage(){return `<div class="grid mainGrid"><div class="card"><h2>Saved Characters</h2><div class="row" style="margin-bottom:10px"><button class="btn" onclick="startNewCharacter()">Create New</button><label class="btn ghost">Import Character<input type="file" accept="application/json" style="display:none" onchange="importCharacter(event)"></label></div>${characterList()}</div><div class="card"><h2>Selected Character</h2>${activeChar()?fullCharacter(activeChar()):'<div class="item small">Select a character from the list.</div>'}</div></div>`}
function selectCharacter(id){state.activeCharacterId=id;state.tab='characters';render()} function startNewCharacter(){let c=defaultCharacter();state.characters.push(c);state.activeCharacterId=c.id;state.wizardStep=0;persist();state.tab='create';render()}
function characterSummary(c){return `<div class="row">${c.profile.image?`<img class="portrait" src="${c.profile.image}">`:`<div class="portrait">${esc((c.profile.name||'W')[0].toUpperCase())}</div>`}<div><h3>${esc(c.profile.name||'Unnamed Warden')}</h3><div>${esc(c.profile.role)} · ${esc(c.profile.lineage||'Unknown lineage')}</div><div class="small">${esc(c.lore.concept||'No concept yet.')}</div></div></div>`}
function fullCharacter(c){return `${characterSummary(c)}<div class="divider"></div><div class="grid cols2">${DATA.attributes.map(a=>`<div class="item"><b>${a.label}</b><div class="small">${esc(a.use||'')}</div><input type="number" value="${c.attributes[a.key]||0}" onchange="editCharAttr('${a.key}',this.value)"></div>`).join('')}</div><div class="divider"></div><label>Notes</label><textarea onchange="editChar('notes',this.value)">${esc(c.notes||'')}</textarea>`}
function editChar(path,val){let c=activeChar(); if(!c)return; let parts=path.split('.'),o=c; for(let i=0;i<parts.length-1;i++)o=o[parts[i]]; o[parts.at(-1)]=val;c.updated=new Date().toISOString();persist()} function editCharAttr(k,v){let c=activeChar();c.attributes[k]=clamp(v,0,30);c.manualAttributeEdits=true;persist()}
function wizard(){let c=activeChar(); if(!c){startNewCharacter();return ''} let step=state.wizardStep;return `<div class="card"><h2>Guided Character Creation</h2><div class="stepper">${['Identity','Lore','Appearance','Role','Attributes','Skills','Equipment','Finish'].map((s,i)=>`<button class="step ${i===step?'active':''}" onclick="state.wizardStep=${i};renderPanel()">${i+1}. ${s}</button>`).join('')}</div><div class="divider"></div>${wizardStep(c,step)}<div class="row spread" style="margin-top:14px"><button class="btn ghost" ${step===0?'disabled':''} onclick="state.wizardStep--;renderPanel()">Back</button><button class="btn" onclick="wizardNext()">${step>=7?'Finish Character':'Next'}</button></div></div>`}
function wizardNext(){if(state.wizardStep<7){state.wizardStep++;renderPanel()}else{persist();state.tab='characters';render()}}
function field(path,label,val){return `<div><label>${label}</label><input value="${esc(val||'')}" onchange="editChar('${path}',this.value)"></div>`}
function area(path,label,val){return `<div><label>${label}</label><textarea onchange="editChar('${path}',this.value)">${esc(val||'')}</textarea></div>`}
function wizardStep(c,step){if(step===0)return `<div class="grid cols2">${field('profile.name','Name',c.profile.name)}${field('profile.lineage','Lineage',c.profile.lineage)}${field('profile.age','Age',c.profile.age)}${field('profile.pronouns','Pronouns / Notes',c.profile.pronouns)}${field('profile.height','Height',c.profile.height)}${field('profile.weight','Weight',c.profile.weight)}${field('profile.backgroundAlias','Background / Alias',c.profile.backgroundAlias)}</div>`;if(step===1)return `<div class="grid cols2">${area('lore.concept','One Sentence Concept',c.lore.concept)}${area('lore.backstory','Backstory',c.lore.backstory)}${area('lore.scar','Supernatural Scar',c.lore.scar)}${area('lore.fear','What They Fear Becoming',c.lore.fear)}${area('lore.goals','Goals',c.lore.goals)}${area('lore.contacts','Contacts / Ties',c.lore.contacts)}</div>`;if(step===2)return `<div class="grid cols2"><div class="center">${c.profile.image?`<img class="portrait big" src="${c.profile.image}">`:`<div class="portrait big" style="margin:auto">IMG</div>`}<label style="margin-top:8px">Upload Character Image</label><input type="file" accept="image/*" onchange="uploadImage(event)"></div><div class="grid">${field('appearance.eyes','Eyes',c.appearance.eyes)}${field('appearance.hair','Hair',c.appearance.hair)}${field('appearance.build','Build',c.appearance.build)}${field('appearance.style','Clothing / Style',c.appearance.style)}${area('appearance.notes','Appearance Notes',c.appearance.notes)}</div></div>`;if(step===3)return `<div class="grid cols2"><div><label>Role</label><select onchange="setRole(this.value)">${Object.keys(DATA.roles).map(r=>`<option ${c.profile.role===r?'selected':''}>${r}</option>`).join('')}</select><div class="note" style="margin-top:10px"><b>${esc(c.profile.role)}</b>: ${esc(roleObj(c.profile.role).function||'')}</div><button class="btn ghost" style="margin-top:10px" onclick="recalcAttributes()">Recalculate Attributes From Role</button></div><div class="list">${Object.entries(roleObj(c.profile.role).bonuses).map(([k,v])=>`<div class="item"><b>${attrLabel(k)}</b> +${v}</div>`).join('')}</div></div>`;if(step===4)return `<div><div class="note">Attributes are base 9 plus role bonuses. Manual edits are allowed, but use Recalculate if the role package looks wrong.</div><div class="grid cols3" style="margin-top:10px">${DATA.attributes.map(a=>`<div class="item"><b>${a.label}</b><div class="small">${esc(a.use||'')}</div><input type="number" value="${c.attributes[a.key]||9}" onchange="editCharAttr('${a.key}',this.value)"></div>`).join('')}</div></div>`;if(step===5){let r=roleObj(c.profile.role);return `<div class="grid cols3"><div class="card"><h3>Starter Skills</h3>${r.starter.map(s=>skillRow(c,s,true)).join('')}<button class="btn full" onclick="applyStarterSkills()">Apply All Starter Skills Rank 1</button></div><div class="card"><h3>Experienced</h3>${r.experienced.map(s=>skillRow(c,s,false)).join('')}</div><div class="card"><h3>Master</h3>${r.master.map(s=>skillRow(c,s,false)).join('')}</div></div>`}if(step===6)return equipmentStep(c);return `<div class="grid cols2"><div class="card"><h3>Review</h3>${characterSummary(c)}<p><b>Role:</b> ${esc(c.profile.role)}</p><p><b>Concept:</b> ${esc(c.lore.concept||'')}</p><p><b>Equipment:</b> ${(c.equipment||[]).map(esc).join(', ')||'None selected'}</p></div><div class="card"><h3>Ready</h3><p>This character is saved to this device and can be exported as JSON.</p><button class="btn" onclick="downloadCharacter('${c.id}')">Download Character JSON</button></div></div>`}
function uploadImage(e){let f=e.target.files[0]; if(!f)return; let r=new FileReader(); r.onload=()=>{editChar('profile.image',r.result);renderPanel()}; r.readAsDataURL(f)}
function setRole(role){let c=activeChar();c.profile.role=role;c.attributes=rolePackage(role);c.manualAttributeEdits=false;persist();renderPanel()} function recalcAttributes(){let c=activeChar();c.attributes=rolePackage(c.profile.role);c.manualAttributeEdits=false;persist();renderPanel()} function applyStarterSkills(){let c=activeChar();roleObj(c.profile.role).starter.forEach(s=>c.skills[s]=Math.max(rank(c,s),1));persist();renderPanel()}
function skillRow(c,s,starter){return `<div class="item row spread"><div><b>${esc(s)}</b><div class="small">${starter?'Starter':'Role skill'}</div></div>${rankBoxes(c,s)}</div>`}
function rankBoxes(c,s){return `<div class="rank">${[1,2,3].map(n=>`<button class="box ${rank(c,s)>=n?'on':''}" onclick="setSkillRank('${s.replace(/'/g,"\\'")}',${rank(c,s)===n?n-1:n})"></button>`).join('')}</div>`}
function setSkillRank(skill,n){let c=activeChar();c.skills[skill]=clamp(n,0,3);persist();renderPanel()}function equipmentStep(c){let packs=DATA.starterEquipmentPackages||{};let packNames=Object.keys(packs);let items=[...DATA.gear,...DATA.consumablesRelics].map(x=>x.name);return `<div class="grid cols2"><div><label>Starting Package</label><select onchange="applyEquipmentPack(this.value)"><option value="">Choose package...</option>${packNames.map(p=>`<option ${c.startingPackage===p?'selected':''}>${p}</option>`).join('')}</select><div class="list" style="margin-top:10px">${items.map(i=>`<label class="item row"><input type="checkbox" style="width:auto" ${c.equipment?.includes(i)?'checked':''} onchange="toggleEquipment('${i.replace(/'/g,"\\'")}',this.checked)"> ${esc(i)}</label>`).join('')}</div></div><div><h3>Current Equipment</h3><div class="list">${(c.equipment||[]).map(i=>`<div class="item row spread"><span>${esc(i)}</span><button class="btn ghost" onclick="toggleEquipment('${i.replace(/'/g,"\\'")}',false);renderPanel()">Remove</button></div>`).join('')||'<div class="item small">No equipment selected.</div>'}</div></div></div>`}
function applyEquipmentPack(p){let c=activeChar();c.startingPackage=p;c.equipment=[...new Set([...(c.equipment||[]),...(DATA.starterEquipmentPackages[p]||[])])];persist();renderPanel()}function toggleEquipment(i,on){let c=activeChar();c.equipment=c.equipment||[]; if(on&&!c.equipment.includes(i))c.equipment.push(i); if(!on)c.equipment=c.equipment.filter(x=>x!==i);persist()}
function levelPage(){let c=activeChar();if(!c)return `<div class="card"><h2>Level Up</h2><p>Select or create a character first.</p></div>`;let r=roleObj(c.profile.role);let sharedLocked=(c.tier||1)<2;return `<div class="grid mainGrid"><div class="card"><h2>Guided Leveling</h2>${characterSummary(c)}<div class="divider"></div><label>Warden Marks</label><input type="number" value="${c.marks||0}" onchange="editChar('marks',clamp(this.value,0,99))"><label style="margin-top:8px">Tier</label><select onchange="editChar('tier',Number(this.value));renderPanel()"><option ${c.tier==1?'selected':''}>1</option><option ${c.tier==2?'selected':''}>2</option><option ${c.tier==3?'selected':''}>3</option></select><div class="note" style="margin-top:10px"><b>Progression Logic:</b> Role skills come first. Shared/acquired skills unlock after Tier 2 in this prototype.</div><div class="list" style="margin-top:10px"><button class="btn ghost" onclick="spendMarks(1,'skill')">Spend 1: Skill Rank Up</button><button class="btn ghost" onclick="spendMarks(3,'tier')">Spend 3: Unlock Next Role Tier</button><button class="btn ghost" onclick="spendMarks(${hasHighStat(c)?6:4},'attribute')">Spend ${hasHighStat(c)?6:4}: Attribute +1</button><button class="btn ghost" ${sharedLocked?'disabled':''} onclick="spendMarks(2,'shared')">Spend 2: Acquired / Shared Skill</button></div></div><div class="card"><h2>Available Skills</h2><div class="grid cols3"><div><h3>Starter</h3>${r.starter.map(s=>skillRow(c,s,true)).join('')}</div><div><h3>Experienced ${c.tier<2?'<span class="small">locked</span>':''}</h3>${r.experienced.map(s=>skillRow(c,s,false)).join('')}</div><div><h3>Master ${c.tier<3?'<span class="small">locked</span>':''}</h3>${r.master.map(s=>skillRow(c,s,false)).join('')}</div></div><div class="divider"></div><h3>Shared Skills ${sharedLocked?'<span class="small">locked until Tier 2</span>':''}</h3><div class="grid cols3">${DATA.sharedSkills.map(s=>`<div class="item ${sharedLocked?'small':''}"><b>${esc(s.name)}</b><div class="small">${esc(s.attribute)} — ${esc(s.use)}</div>${!sharedLocked?rankBoxes(c,s.name):''}</div>`).join('')}</div></div></div>`}
function hasHighStat(c){return Object.values(c.attributes||{}).some(v=>Number(v)>=12)} function spendMarks(cost,type){let c=activeChar();if((c.marks||0)<cost)return alert('Not enough Warden Marks.');c.marks-=cost;if(type==='tier')c.tier=Math.min(3,(c.tier||1)+1);persist();renderPanel()}
function campaignsPage(){return `<div class="grid campaignGrid"><div class="card"><h2>Campaign List</h2><div class="row" style="margin-bottom:10px"><button class="btn" onclick="createCampaign()">Create</button><button class="btn ghost" onclick="joinCampaignPrompt()">Join</button></div>${campaignList()}<div class="divider"></div><label>Import Campaign</label><input type="file" accept="application/json" onchange="importCampaign(event)"></div><div class="card"><h2>Campaign Manager</h2>${activeCamp()?campaignDetail(activeCamp()):'<div class="item small">Select or create a campaign.</div>'}</div></div>`}
function campaignList(compact=false){let camps=state.campaigns.filter(c=>!state.account||!c.ownerId||c.ownerId===state.account.id||c.memberIds?.includes(state.account.id)||c.players?.some(p=>p.id===state.account.id||p.email===state.account.email));if(!camps.length)return '<div class="item small">No campaigns saved yet.</div>';return `<div class="list">${camps.map(c=>`<div class="item ${state.activeCampaignId===c.id?'active':''}"><b>${esc(c.name)}</b><div class="small">Code ${esc(c.joinCode)} · ${c.players?.length||0} players · ${c.chats?.length||0} chats ${c.autoGM?'· Auto-GM':''}</div><div class="row" style="margin-top:8px"><button class="btn ghost" onclick="selectCampaign('${c.id}')">Open</button><button class="btn ghost" onclick="downloadCampaign('${c.id}')">Export</button><button class="btn bad" onclick="deleteCampaign('${c.id}')">Delete</button></div></div>`).join('')}</div>`}
function createCampaign(){let c=newCampaign();state.campaigns.push(c);state.activeCampaignId=c.id;persist();state.tab='campaigns';render()} function selectCampaign(id){let c=state.campaigns.find(x=>x.id===id);state.activeCampaignId=id;persist();if(c&&c.autoGM){window.location.href='auto-gm.html?campaignId='+encodeURIComponent(c.id)+'&campaignCode='+encodeURIComponent(c.joinCode||'')+'&caseId='+encodeURIComponent(c.activeAutoGmCaseId||'main')+'&v=7';return}state.tab='campaigns';render()} async function joinCampaignPrompt(){let code=(prompt('Enter campaign join code')||'').toUpperCase().trim(); if(!code)return; if(FB.ready&&FB.user){let found=await cloudJoinCampaign(code); if(found){state.activeCampaignId=found.id;state.tab='campaigns';render();return}} let c=state.campaigns.find(x=>x.joinCode===code); if(c){c.memberIds=c.memberIds||[];if(!c.memberIds.includes(state.account.id))c.memberIds.push(state.account.id);if(!c.players.some(p=>p.id===state.account.id))c.players.push({id:state.account.id,name:state.account.displayName,email:state.account.email,role:'Player'});state.activeCampaignId=c.id;persist();render()}else{let nc=newCampaign();nc.name='Joined Campaign';nc.joinCode=code;nc.players=[{id:state.account.id,name:state.account.displayName,email:state.account.email,role:'Player'}];nc.memberIds=[state.account.id];state.campaigns.push(nc);state.activeCampaignId=nc.id;persist();render()}}
function campaignDetail(c){return `<div class="grid cols2"><div><label>Campaign Name</label><input value="${esc(c.name)}" onchange="editCampaign('name',this.value)"></div><div><label>Join Code</label><input value="${esc(c.joinCode)}" onchange="editCampaign('joinCode',this.value.toUpperCase())"></div></div><label style="margin-top:8px">Summary</label><textarea onchange="editCampaign('summary',this.value)">${esc(c.summary||'')}</textarea><div class="divider"></div><label class="row" style="font-size:13px;text-transform:none;letter-spacing:0"><input type="checkbox" style="width:auto" ${c.autoGM?'checked':''} onchange="editCampaign('autoGM',this.checked)"> Use Auto-GM for this campaign</label>${c.autoGM?`<div class="note"><b>Auto-GM Enabled:</b> opening this campaign from the list launches the separate Auto-GM page. <button class="btn ghost" onclick="openAutoGmForCampaign()">Open Auto-GM Now</button></div>`:''}<div class="divider"></div><h3>Players</h3><div class="row"><input id="playerName" placeholder="Player name"><input id="playerEmail" placeholder="email/handle"><button class="btn ghost" onclick="addPlayer()">Add Player</button></div><div class="list" style="margin-top:8px">${(c.players||[]).map((p,i)=>`<div class="item row spread"><span>${esc(p.name)} <span class="small">${esc(p.email||'')}</span> <span class="pill">${esc(p.role||'Player')}</span></span><button class="btn ghost" onclick="removePlayer(${i})">Remove</button></div>`).join('')||'<div class="item small">No players yet.</div>'}</div><div class="divider"></div><h3>Characters in Campaign</h3><div class="row"><select id="campCharSelect">${state.characters.map(ch=>`<option value="${ch.id}">${esc(ch.profile.name||'Unnamed')} (${esc(ch.profile.role)})</option>`).join('')}</select><button class="btn ghost" onclick="addCharacterToCampaign()">Add Character</button></div><div class="list" style="margin-top:8px">${(c.characters||[]).map(id=>state.characters.find(ch=>ch.id===id)).filter(Boolean).map(ch=>`<div class="item">${esc(ch.profile.name||'Unnamed')} · ${esc(ch.profile.role)}</div>`).join('')||'<div class="item small">No characters assigned.</div>'}</div><div class="divider"></div><h3>Campaign Chats</h3><div class="row"><input id="chatName" placeholder="New chat name"><button class="btn ghost" onclick="addChat()">Add Chat</button></div>${chatArea(c)}`}
function editCampaign(k,v){let c=activeCamp();c[k]=v;c.updated=new Date().toISOString();persist()} function openAutoGmForCampaign(){let c=activeCamp();if(!c)return;persist();window.location.href='auto-gm.html?campaignId='+encodeURIComponent(c.id)+'&campaignCode='+encodeURIComponent(c.joinCode||'')+'&caseId='+encodeURIComponent(c.activeAutoGmCaseId||'main')+'&v=7'} function addPlayer(){let c=activeCamp();c.players=c.players||[];let email=$('#playerEmail').value||'';let pid=uid('player');c.players.push({id:pid,name:$('#playerName').value||'Player',email:email,role:'Player'});c.memberEmails=[...new Set([...(c.memberEmails||[]),email].filter(Boolean))];persist();renderPanel()} function removePlayer(i){activeCamp().players.splice(i,1);persist();renderPanel()} function addCharacterToCampaign(){let c=activeCamp();let id=$('#campCharSelect').value;c.characters=c.characters||[];if(id&&!c.characters.includes(id))c.characters.push(id);persist();renderPanel()} function addChat(){let c=activeCamp();c.chats.push({id:uid('chat'),name:$('#chatName').value||'New Chat',visibleTo:'all',members:[],messages:[]});persist();renderPanel()}
function chatArea(c){let chat=c.chats?.[0];return `<div class="note" style="margin-top:10px"><b>Local privacy:</b> Chats are saved on this device. True player-only visibility requires online accounts + database rules.</div><div class="chatBox" style="margin-top:10px">${(chat?.messages||[]).map(m=>`<div class="msg"><div class="meta">${esc(m.author)} · ${new Date(m.time).toLocaleString()}</div>${esc(m.text)}</div>`).join('')||'<div class="small">No messages yet.</div>'}</div><div class="row" style="margin-top:8px"><input id="chatMsg" placeholder="Write campaign note/chat..."><button class="btn" onclick="sendChat('${chat?.id}')">Send</button></div>`}function sendChat(id){let c=activeCamp();let chat=c.chats.find(x=>x.id===id);let txt=$('#chatMsg').value.trim();if(!txt)return;chat.messages.push({id:uid('msg'),author:state.account.displayName,time:new Date().toISOString(),text:txt});persist();renderPanel()}
function textList(txt){return esc(txt||'').replace(/\n/g,'<br>')}
function library(){let q=(state.query||'').toLowerCase(),cards=[];function push(title,type,body,meta){let o={title,type,body,meta}; if(JSON.stringify(o).toLowerCase().includes(q))cards.push(o)}(DATA.sharedSkills||[]).forEach(x=>push(x.name,'Shared Skill',x.use,x.attribute));Object.entries(DATA.roles||{}).forEach(([role,r])=>[...r.starter,...r.experienced,...r.master].forEach(s=>push(s,role+' Role Skill','Role skill from the '+role+' ladder.','Starter/Experienced/Master')));(DATA.gear||[]).forEach(x=>push(x.name,x.type,x.effect,'Gear'));(DATA.consumablesRelics||[]).forEach(x=>push(x.name,x.type,x.effect,x.cost));(DATA.materials||[]).forEach(x=>push(x.name,x.category,x.function,'Material'));return `<div class="card"><h2>Complete Field Library</h2><p class="small">This general archive covers role skills, shared skills, gear, relics, and materials. Use the Grimoire and Bestiary tabs for dedicated flip-through archive pages.</p><input placeholder="Search skills, gear, relics, materials..." value="${esc(state.query)}" oninput="state.query=this.value;renderPanel()"><div class="library grid cols3" style="margin-top:12px">${cards.map(c=>`<div class="item"><span class="pill">${esc(c.type)}</span><h3>${esc(c.title)}</h3><p class="small">${esc(c.meta)}</p><p>${esc(c.body)}</p>${activeChar()?`<button class="btn ghost" onclick="addToCharacter('${c.title.replace(/'/g,"\\'")}')">Add to Character</button>`:''}</div>`).join('')}</div></div>`}
function grimoirePage(){state.grimoireQuery=state.grimoireQuery||'';state.grimoireKind=state.grimoireKind||'all';state.grimoireIndex=state.grimoireIndex||0;let q=state.grimoireQuery.toLowerCase();let kinds=['all',...new Set((DATA.spells||[]).map(s=>s.kind||'Occult'))];let list=(DATA.spells||[]).filter(s=>(state.grimoireKind==='all'||s.kind===state.grimoireKind)&&JSON.stringify(s).toLowerCase().includes(q));if(state.grimoireIndex>=list.length)state.grimoireIndex=0;let cur=list[state.grimoireIndex];return `<div class="grid campaignGrid"><div class="card"><h2>Warden Grimoire</h2><p class="small">Known spells, rites, curses, blessings, forbidden workings, and spell seeds cataloged for field use.</p><label>Search description, roll, signs, effects, backlash</label><input value="${esc(state.grimoireQuery)}" placeholder="ex: possession, ward, spirit, fear, anchor..." oninput="state.grimoireQuery=this.value;state.grimoireIndex=0;renderPanel()"><label style="margin-top:8px">Filter Type</label><select onchange="state.grimoireKind=this.value;state.grimoireIndex=0;renderPanel()">${kinds.map(k=>`<option value="${esc(k)}" ${state.grimoireKind===k?'selected':''}>${esc(k)}</option>`).join('')}</select><div class="divider"></div><div class="row spread"><button class="btn ghost" onclick="state.grimoireIndex=Math.max(0,(state.grimoireIndex||0)-1);renderPanel()">Previous</button><span class="pill">${list.length?state.grimoireIndex+1:0} / ${list.length}</span><button class="btn ghost" onclick="state.grimoireIndex=Math.min(${Math.max(0,list.length-1)},(state.grimoireIndex||0)+1);renderPanel()">Next</button></div><div class="divider"></div><div class="library list">${list.map((s,i)=>`<button class="item ${i===state.grimoireIndex?'active':''}" style="text-align:left" onclick="state.grimoireIndex=${i};renderPanel()"><b>${esc(s.name)}</b><div class="small">${esc(s.kind||'Occult')} · ${esc(s.roll||'')}</div></button>`).join('')||'<div class="item small">No matching spells or rites.</div>'}</div></div><div class="card">${cur?spellCard(cur):'<h2>No Grimoire Entry</h2>'}</div></div>`}
function spellCard(s){return `<h2>${esc(s.name)}</h2><div class="row"><span class="pill">${esc(s.kind||'Occult')}</span>${s.school?`<span class="pill">${esc(s.school)}</span>`:''}</div><div class="grid cols2" style="margin-top:12px"><div class="item"><b>Roll</b><br>${esc(s.roll||'—')}</div><div class="item"><b>Cost / Cast</b><br>${esc(s.cost||'—')}</div></div><div class="item" style="margin-top:10px"><b>Effect / Use</b><p>${textList(s.effect||s.use||'')}</p></div>${s.backlash?`<div class="item"><b>Backlash</b><p>${textList(s.backlash)}</p></div>`:''}${s.components?`<div class="item"><b>Components</b><p>${textList(s.components)}</p></div>`:''}${activeChar()?`<button class="btn" onclick="addToCharacter('${s.name.replace(/'/g,"\\'")}')">Add Spell / Rite to Character</button>`:''}<div class="divider"></div><h3>Occult Schools</h3><div class="grid cols2">${(DATA.occultSchools||[]).map(o=>`<div class="item"><b>${esc(o.name)}</b><div class="small">${esc(o.role)}</div></div>`).join('')}</div>`}
function bestiaryPage(){state.bestiaryQuery=state.bestiaryQuery||'';state.bestiaryCategory=state.bestiaryCategory||'all';state.bestiaryIndex=state.bestiaryIndex||0;let q=state.bestiaryQuery.toLowerCase();let cats=['all',...new Set((DATA.bestiary||[]).map(b=>b.category||b.type||'Entity'))];let list=(DATA.bestiary||[]).filter(b=>(state.bestiaryCategory==='all'||b.category===state.bestiaryCategory)&&JSON.stringify(b).toLowerCase().includes(q));if(state.bestiaryIndex>=list.length)state.bestiaryIndex=0;let cur=list[state.bestiaryIndex];return `<div class="grid campaignGrid"><div class="card"><h2>Warden Bestiary</h2><p class="small">Known creatures and entities by the Warden organization. Search signs, sightings, behavior, effects, weakness, or kill condition.</p><label>Search signs, sightings, effects, weakness</label><input value="${esc(state.bestiaryQuery)}" placeholder="ex: sulfur, mirrors, hunger, children, iron, fire..." oninput="state.bestiaryQuery=this.value;state.bestiaryIndex=0;renderPanel()"><label style="margin-top:8px">Filter Type</label><select onchange="state.bestiaryCategory=this.value;state.bestiaryIndex=0;renderPanel()">${cats.map(c=>`<option value="${esc(c)}" ${state.bestiaryCategory===c?'selected':''}>${esc(c)}</option>`).join('')}</select><div class="divider"></div><div class="row spread"><button class="btn ghost" onclick="state.bestiaryIndex=Math.max(0,(state.bestiaryIndex||0)-1);renderPanel()">Previous</button><span class="pill">${list.length?state.bestiaryIndex+1:0} / ${list.length}</span><button class="btn ghost" onclick="state.bestiaryIndex=Math.min(${Math.max(0,list.length-1)},(state.bestiaryIndex||0)+1);renderPanel()">Next</button></div><div class="divider"></div><div class="library list">${list.map((b,i)=>`<button class="item ${i===state.bestiaryIndex?'active':''}" style="text-align:left" onclick="state.bestiaryIndex=${i};renderPanel()"><b>${esc(b.name)}</b><div class="small">${esc(b.category||'Entity')} · ${esc(b.type||'')} · Threat ${esc(b.threat||'?')}</div></button>`).join('')||'<div class="item small">No matching archive entries.</div>'}</div></div><div class="card">${cur?beastCard(cur):'<h2>No Bestiary Entry</h2>'}</div></div>`}
function beastCard(b){return `<h2>${esc(b.name)}</h2><div class="row"><span class="pill">${esc(b.category||'Entity')}</span><span class="pill">${esc(b.type||'Unknown Type')}</span><span class="pill">Threat ${esc(b.threat||'?')}</span></div><div class="grid cols2" style="margin-top:12px"><div class="item"><b>Signs / Sightings</b><p>${textList(b.signs||'No signs recorded.')}</p></div><div class="item"><b>Behavior</b><p>${textList(b.behavior||'No behavior recorded.')}</p></div><div class="item"><b>Effects</b><p>${textList(b.effects||'No effect recorded.')}</p></div><div class="item"><b>Weakness</b><p>${textList(b.weakness||'Unknown.')}</p></div></div><div class="item" style="margin-top:10px"><b>Abilities</b><p>${textList(b.abilities||'No abilities recorded.')}</p></div><div class="item"><b>Summon / Trigger / Manifestation</b><p>${textList(b.summonTrigger||'Unknown.')}</p></div>${b.traps?`<div class="item"><b>Traps That Work</b><p>${textList(b.traps)}</p></div>`:''}<div class="darknote"><b>Kill / End Condition</b><br>${textList(b.killCondition||'Unknown. Do not assume damage is enough.')}</div>`}
function addToCharacter(name){let c=activeChar();if(!c)return;let isItem=[...DATA.gear,...DATA.consumablesRelics,...DATA.materials].some(x=>x.name===name);if(isItem)c.equipment=[...new Set([...(c.equipment||[]),name])];else c.skills[name]=Math.max(rank(c,name),1);persist();renderPanel()}
function roller(){let c=activeChar();let skills=allSkills();return `<div class="grid campaignGrid"><div class="card"><h2>Dice Roller</h2>${!c?'<div class="note">Load a character first.</div>':''}<div class="grid cols2"><div><label>Dice</label><select onchange="state.roller.dice=this.value"><option ${state.roller.dice==='3d6'?'selected':''}>3d6</option><option ${state.roller.dice==='2d6'?'selected':''}>2d6</option></select></div><div><label>Setbacks</label><input type="number" value="${state.roller.setbacks}" onchange="state.roller.setbacks=clamp(this.value,0,12)"></div></div><label>Attribute</label><select onchange="state.roller.attr=this.value">${DATA.attributes.map(a=>`<option value="${a.key}" ${state.roller.attr===a.key?'selected':''}>${a.label} ${c?'('+c.attributes[a.key]+')':''}</option>`).join('')}</select><label>Primary Skill</label><select onchange="state.roller.primary=this.value">${skills.map(s=>`<option ${state.roller.primary===s?'selected':''}>${esc(s)} ${c?'r'+rank(c,s):''}</option>`).join('')}</select><div class="grid cols2"><div><label>Support 1</label><select onchange="state.roller.support1=this.value"><option value="none">None</option>${skills.map(s=>`<option ${state.roller.support1===s?'selected':''}>${esc(s)} ${c?'r'+rank(c,s):''}</option>`).join('')}</select></div><div><label>Support 2</label><select onchange="state.roller.support2=this.value"><option value="none">None</option>${skills.map(s=>`<option ${state.roller.support2===s?'selected':''}>${esc(s)} ${c?'r'+rank(c,s):''}</option>`).join('')}</select></div></div><button class="btn full" style="margin-top:10px" onclick="rollCheck()">Roll Check</button></div><div class="card"><h2>Roll Log</h2><div class="list">${state.rolls.map(r=>`<div class="item"><div class="row spread"><b>${esc(r.label)}</b><span class="pill ${r.success?'successText':'dangerText'}">${r.success?'SUCCESS':'FAIL'}</span></div><div>Rolled <span class="inlineRoll">${r.dice.join(' + ')} = ${r.total}</span> vs Target <b>${r.target}</b></div><div class="small">${esc(r.detail)} · ${r.time}</div></div>`).join('')||'<div class="item small">No rolls yet.</div>'}</div></div></div>`}
function rollCheck(){let c=activeChar();if(!c)return alert('Load a character first.');let count=state.roller.dice==='2d6'?2:3,dice=Array.from({length:count},()=>Math.floor(Math.random()*6)+1),total=dice.reduce((a,b)=>a+b,0),attr=c.attributes[state.roller.attr]||0,p=rank(c,state.roller.primary),s1=state.roller.support1==='none'?0:rank(c,state.roller.support1),s2=state.roller.support2==='none'?0:rank(c,state.roller.support2),support=Math.min(2,(s1>0?1:0)+(s2>0?1:0)),target=attr+p-Math.max(0,Number(state.roller.setbacks||0)-support);state.rolls.unshift({id:uid('roll'),label:`${attrLabel(state.roller.attr)} + ${state.roller.primary}`,dice,total,target,success:total<=target,detail:`Attr ${attr} + skill ${p} - setbacks ${state.roller.setbacks} + support offset ${support}`,time:new Date().toLocaleTimeString()});state.rolls=state.rolls.slice(0,20);renderPanel()}
function refTable(title, rows){return `<div class="card"><h2>${esc(title)}</h2><div class="list">${rows.map(r=>`<div class="item"><b>${esc(r[0])}</b><div>${esc(r[1])}</div></div>`).join('')}</div></div>`}
function reference(){let q=DATA.quickReference||{};return `<div class="card"><h2>Warden Field Quick Reference</h2><p class="small">Combat / Movement / Actions / Inspections. This page follows the uploaded quick reference sheet.</p><div class="grid cols4">${(q.core||[]).map(x=>`<div class="darknote"><b>${esc(x.label)}</b><br>${esc(x.text)}</div>`).join('')}</div></div><div class="grid cols2" style="margin-top:14px">${refTable('Round Flow',q.roundFlow||[])}${refTable('Combat Actions',q.combatActions||[])}${refTable('Reactions & Damage',q.reactionsDamage||[])}${refTable('Prep Wins Hunts',q.prepWinsHunts||[])}${refTable('Movement',q.movement||[])}${refTable('Actions at a Glance',q.actions||[])}${refTable('Inspections / Investigation',q.investigation||[])}${refTable('Control / Afflictions',q.control||[])}</div><div class="card" style="margin-top:14px"><h2>Case Mantra</h2><div class="darknote">${esc(q.mantra||'Investigate first, prepare second, confront last.')}</div></div>`}
function createCampaignDownload(c){download((c.name||'night_wardens_campaign').replace(/\W+/g,'_')+'.json',JSON.stringify(c,null,2))}function downloadCampaign(id){let c=state.campaigns.find(x=>x.id===id);download((c.name||'night_wardens_campaign').replace(/\W+/g,'_')+'.json',JSON.stringify(c,null,2))}function deleteCampaign(id){if(!confirm('Delete campaign from this device?'))return;state.campaigns=state.campaigns.filter(c=>c.id!==id);if(state.activeCampaignId===id)state.activeCampaignId=null;persist();render()}
function importCampaign(e){let f=e.target.files[0];if(!f)return;let r=new FileReader();r.onload=()=>{try{let c=JSON.parse(r.result);c.id=c.id||uid('camp');let i=state.campaigns.findIndex(x=>x.id===c.id);if(i>=0)state.campaigns[i]=c;else state.campaigns.push(c);state.activeCampaignId=c.id;persist();render()}catch{alert('Invalid campaign JSON')}};r.readAsText(f)}
function download(filename,text){let a=document.createElement('a');a.href=URL.createObjectURL(new Blob([text],{type:'application/json'}));a.download=filename;a.click();setTimeout(()=>URL.revokeObjectURL(a.href),500)}function exportVault(){download('night_wardens_vault.json',JSON.stringify({version:6,account:state.account,accounts:state.accounts,characters:state.characters,campaigns:state.campaigns},null,2))}function importVault(e){let f=e.target.files[0];if(!f)return;let r=new FileReader();r.onload=()=>{try{let v=JSON.parse(r.result);if(Array.isArray(v.accounts))state.accounts=v.accounts;if(v.account)state.account=v.account;if(Array.isArray(v.characters))state.characters=v.characters;if(Array.isArray(v.campaigns))state.campaigns=v.campaigns;persist();render()}catch{alert('Invalid vault JSON')}};r.readAsText(f)}function importVaultFromLanding(e){let f=e.target.files[0];if(!f)return;let r=new FileReader();r.onload=()=>{try{let v=JSON.parse(r.result);if(Array.isArray(v.accounts))state.accounts=v.accounts;if(Array.isArray(v.characters))state.characters=v.characters;if(Array.isArray(v.campaigns))state.campaigns=v.campaigns;if(v.account){state.account=v.account;state.view='app'}persist();render()}catch{alert('Invalid vault JSON')}};r.readAsText(f)}function downloadCharacter(id){let c=state.characters.find(x=>x.id===id);download((c.profile.name||'night_warden_character').replace(/\W+/g,'_')+'.json',JSON.stringify(c,null,2))}function importCharacter(e){let f=e.target.files[0];if(!f)return;let r=new FileReader();r.onload=()=>{try{let c=JSON.parse(r.result);c.id=c.id||uid('char');c.ownerId=c.ownerId||state.account?.id||'local';let i=state.characters.findIndex(x=>x.id===c.id);if(i>=0)state.characters[i]=c;else state.characters.push(c);state.activeCharacterId=c.id;persist();render()}catch{alert('Invalid character JSON')}};r.readAsText(f)}function deleteCharacter(id){if(!confirm('Delete character from this device?'))return;state.characters=state.characters.filter(c=>c.id!==id);if(state.activeCharacterId===id)state.activeCharacterId=null;persist();render()}


// ---------------- Firebase Auth + Firestore optional backend ----------------
async function initFirebase(force=false){
  if(FB.ready) return true;
  const cfg=window.NW_FIREBASE_CONFIG;
  if(!cfg||!cfg.apiKey||String(cfg.apiKey).startsWith('PASTE_')){FB.lastSync='Local only — Firebase not configured';if(force)render();return false;}
  if(FB.enabled&&!force) return false;
  FB.enabled=true;
  try{
    const appMod=await import('https://www.gstatic.com/firebasejs/10.12.5/firebase-app.js');
    const authMod=await import('https://www.gstatic.com/firebasejs/10.12.5/firebase-auth.js');
    const fsMod=await import('https://www.gstatic.com/firebasejs/10.12.5/firebase-firestore.js');
    const app=appMod.initializeApp(cfg);
    const auth=authMod.getAuth(app);
    await authMod.setPersistence(auth,authMod.browserLocalPersistence);
    const db=fsMod.getFirestore(app);
    FB={...FB,ready:true,app,auth,db,provider:new authMod.GoogleAuthProvider(),mods:{...authMod,...fsMod},lastSync:'Cloud ready'};
    authMod.onAuthStateChanged(auth,async user=>{
      if(user){
        FB.user=user;
        let acc={id:user.uid,email:user.email||'',displayName:user.displayName||user.email||'Warden',image:user.photoURL||'',remember:true,provider:'google'};
        state.account=acc;state.view='app';
        let existing=state.accounts.find(a=>a.id===acc.id)||state.accounts.find(a=>a.email===acc.email);
        if(existing)Object.assign(existing,acc);else state.accounts.push(acc);
        await loadCloudVault();
        persistLocalOnly();
        render();
      }else{
        FB.user=null;
        if(state.account?.provider==='google'){state.account=null;state.view='landing';save(LS.session,null);render();}
      }
    });
    return true;
  }catch(e){console.error(e);FB.lastSync='Firebase load failed';if(force)alert('Firebase could not initialize: '+(e.message||e));return false;}
}
function persistLocalOnly(){save(LS.accounts,state.accounts);save(LS.characters,state.characters);save(LS.campaigns,state.campaigns);save(LS.session,state.account?{accountId:state.account.id,remember:!!state.account.remember}:null)}
function queueCloudSave(){
  if(FB.loadingCloud||!FB.ready||!FB.user) return;
  clearTimeout(FB.saveTimer);
  FB.saveTimer=setTimeout(()=>saveCloudVault().catch(e=>{console.error(e);FB.lastSync='Cloud save failed';renderPanel()}),900);
}
function normalizeCampaign(c){
  const memberIds=[...new Set([...(c.memberIds||[]),c.ownerId,c.ownerUid,(state.account?.id)].filter(Boolean))];
  const players=(c.players||[]).map(p=>({...p}));
  if(state.account&&!players.some(p=>p.id===state.account.id))players.push({id:state.account.id,name:state.account.displayName,email:state.account.email||'',role:c.ownerId===state.account.id?'GM':'Player'});
  return {...c,memberIds,players,updated:new Date().toISOString()};
}
async function saveCloudVault(){
  if(!FB.ready||!FB.user)return;
  const {doc,setDoc,collection}=FB.mods;
  const uid=FB.user.uid;
  await setDoc(doc(FB.db,'users',uid),{uid,email:state.account.email||'',displayName:state.account.displayName||'',photoURL:state.account.image||'',updatedAt:new Date().toISOString()},{merge:true});
  for(const ch of state.characters.filter(c=>!c.ownerId||c.ownerId===uid||c.ownerId==='local')){
    const out={...ch,ownerId:uid,updated:ch.updated||new Date().toISOString()};
    await setDoc(doc(collection(FB.db,'users',uid,'characters'),out.id),out,{merge:true});
  }
  for(const camp0 of state.campaigns){
    const camp=normalizeCampaign(camp0);
    if(!camp.memberIds.includes(uid)) continue;
    await setDoc(doc(FB.db,'campaigns',camp.id),camp,{merge:true});
    if(camp.joinCode) await setDoc(doc(FB.db,'joinCodes',camp.joinCode),{campaignId:camp.id,ownerId:camp.ownerId||uid,updatedAt:new Date().toISOString()},{merge:true});
  }
  FB.lastSync='Synced '+new Date().toLocaleTimeString();
}
async function loadCloudVault(){
  if(!FB.ready||!FB.user)return;
  FB.loadingCloud=true;
  try{
    const {collection,getDocs,query,where}=FB.mods;
    const uid=FB.user.uid;
    const charSnap=await getDocs(collection(FB.db,'users',uid,'characters'));
    const cloudChars=charSnap.docs.map(d=>d.data());
    mergeById(state.characters,cloudChars);
    const campSnap=await getDocs(query(collection(FB.db,'campaigns'),where('memberIds','array-contains',uid)));
    const cloudCamps=campSnap.docs.map(d=>d.data());
    mergeById(state.campaigns,cloudCamps);
    FB.lastSync='Loaded cloud '+new Date().toLocaleTimeString();
  }catch(e){console.error(e);FB.lastSync='Cloud load failed: '+(e.message||e)}
  FB.loadingCloud=false;
}
function mergeById(local,cloud){
  for(const item of cloud){
    const i=local.findIndex(x=>x.id===item.id);
    if(i<0)local.push(item);
    else{
      const lu=Date.parse(local[i].updated||local[i].created||0), cu=Date.parse(item.updated||item.created||0);
      if(cu>=lu)local[i]=item;
    }
  }
}
async function cloudPull(){await loadCloudVault();persistLocalOnly();render()}
async function cloudPush(){await saveCloudVault();render()}
async function cloudSyncNow(){if(!FB.ready){await initFirebase(true)} if(!FB.ready)return; await saveCloudVault(); await loadCloudVault(); persistLocalOnly(); render()}
async function cloudJoinCampaign(code){
  try{
    const {doc,getDoc,updateDoc,arrayUnion}=FB.mods;
    const codeSnap=await getDoc(doc(FB.db,'joinCodes',code));
    if(!codeSnap.exists()) return null;
    const campaignId=codeSnap.data().campaignId;
    const campRef=doc(FB.db,'campaigns',campaignId);
    const uid=FB.user.uid;
    await updateDoc(campRef,{memberIds:arrayUnion(uid),players:arrayUnion({id:uid,name:state.account.displayName,email:state.account.email||'',role:'Player'}),updated:new Date().toISOString()});
    const campSnap=await getDoc(campRef);
    if(campSnap.exists()){
      const camp=campSnap.data();
      mergeById(state.campaigns,[camp]);persistLocalOnly();FB.lastSync='Joined cloud campaign';return camp;
    }
  }catch(e){console.error(e);alert('Cloud join failed. If this is the first deploy, check Firestore rules and authorized domains. '+(e.message||e));}
  return null;
}

if('serviceWorker' in navigator){window.addEventListener('load',()=>navigator.serviceWorker.register('service-worker.js').catch(()=>{}))}
init();
